        } else {
            // fallback：沒有停輪 node 時從 pool 取
            const symbolNode = PrefabPoolManager.GetInstance().GetNode(symbolPrefabKey);
            if (symbolNode) {
                const spine = symbolNode.getComponent(BaseSpine);
                if (spine) {
                    symbolNode.setParent(this.m_effectNodes[Game_Define.LAYERS.SCATTER]);
                    symbolNode.setWorldPosition(worldPos);
                    symbolNode.active = true;
                    spine.PlayAnimation("Active", spine.Spine, false).then(() => {
                        symbolNode.active = false;
                        PrefabPoolManager.GetInstance().ReturnNode(symbolPrefabKey, symbolNode);
                    });
                } else {
                    PrefabPoolManager.GetInstance().ReturnNode(symbolPrefabKey, symbolNode);
                }
            }
        }

        // Target_Explode 音效提早 0.5s
        Define.Wait(this.m_gameView, 0.5).then(() => {
            AudioManager.Play(AudioManager.AudioClips.Target_Explode);
        });
        // Target_Explode spine（立即播）
        {
            const explodeNode = PrefabPoolManager.GetInstance().GetNode(TARGET_EXPLODE_PREFAB_KEY);
            if (explodeNode) {
                const baseSpine = explodeNode.getComponent(BaseSpine);
                if (baseSpine) {
                    explodeNode.setParent(this.m_effectNodes[Game_Define.LAYERS.TARGET]);
                    explodeNode.setWorldPosition(worldPos);
                    explodeNode.active = true;
                    baseSpine.PlayAnimation(explodeAnimName, baseSpine.Spine, false).then(() => {
                        explodeNode.active = false;
                        PrefabPoolManager.GetInstance().ReturnNode(TARGET_EXPLODE_PREFAB_KEY, explodeNode);
                    });
                } else {
                    PrefabPoolManager.GetInstance().ReturnNode(TARGET_EXPLODE_PREFAB_KEY, explodeNode);
                }
            }
        }
    }

    await Define.Wait(this.m_gameView, 1.5);
}

async ShowMultiplyFlyEffect(pos: number, winValue: string, isLeft: boolean) {
    let targetPos = this.m_gameView.SlotReels.GetMiddleSymbolEmptyNodeFromPosition(pos).getWorldPosition();
    let multiplyFlyNode = PrefabPoolManager.GetInstance().GetNode(MULTI_FLY_PREFAB_KEY);
    if (!multiplyFlyNode) {
        error("multiplyFlyNode");
        return;
    }
    let multiplyFly = multiplyFlyNode.getComponent(MultiplyFlyUI);
    if (!multiplyFly) {
        error("multiplyFly");
        return;
    }
    multiplyFlyNode.setParent(this.m_effectNodes[Game_Define.LAYERS.MULTI_FLY]);
    multiplyFlyNode.setWorldPosition(targetPos);
    multiplyFlyNode.active = true;

    let promises: Promise<void>[] = [];
    promises.push( new Promise(
        async ( resolve ) =>
        {
            multiplyFly.SetWinValue(winValue);
            await multiplyFly.ShowWinValue(isLeft);
            resolve();
        }
    ) );
    await Promise.all( promises );
    PrefabPoolManager.GetInstance().ReturnNode(MULTI_FLY_PREFAB_KEY, multiplyFlyNode);
}

