        // 該列有 Target 時，Target 落地建立 spine（掛在 cell node 上自動跟隨掉落）
        for (let row = 0; row < visibleSymbolCount; row++) {
            const symbolId = this.GetSymbolIdFromServerPlateInfo(col, row);
            if (symbolId === Game_Define.Symbol.Target || symbolId === Game_Define.Symbol.GoldTarget) {
                const capturedCol = col;
                const capturedRow = row;
                const newPosition = Common.GetPositionFromColRow(col, row);

                // 找同 col 已有的 target spine
                let existingKey: number = -1;
                let existingInfo: {node: Node, prefabKey: string} = null;
                const targetWorldPos = this.GetSymbolInitWorldPositionFromColRow(col, row);
                log(`[Target] StartFall col=${col} row=${row} mapSize=${this.m_gameView.EffectPlate.GetAllTargetStopNodes().size} targetX=${targetWorldPos.x.toFixed(1)}`);
                for (const [key, info] of this.m_gameView.EffectPlate.GetAllTargetStopNodes()) {
                    if (info && info.node.active) {
                        const spineWorldPos = info.node.getWorldPosition();
                        log(`[Target]   key=${key} spineX=${spineWorldPos.x.toFixed(1)} spineY=${spineWorldPos.y.toFixed(1)} dx=${Math.abs(spineWorldPos.x - targetWorldPos.x).toFixed(1)}`);
                        if (Math.abs(spineWorldPos.x - targetWorldPos.x) < 30) {
                            existingInfo = info;
                            existingKey = key;
                            break;
                        }
                    }
                }

                if (existingInfo) {
                    // 已有 spine → 同步 tween 跟隨掉落到新位置
                    this.m_gameView.EffectPlate.GetAllTargetStopNodes().delete(existingKey);
                    const spineParent = existingInfo.node.parent;
                    const targetLocalPos = new Vec3();
                    spineParent.inverseTransformPoint(targetLocalPos, targetWorldPos);
                    const capturedInfo = existingInfo;
                    const fallDelay = (this.m_gameView.IsHardStop ? 0 : SYMBOL_FALL_EFFECT_COLUMN_DELAY_TIME * col) + SYMBOL_FALL_EFFECT_ROW_DELAY_TIME * (visibleSymbolCount - 1 - row);
                    const fallTime = SYMBOL_ENTER_MOVE_TIME;
                    tween(existingInfo.node)
                        .delay(fallDelay)
                        .to(fallTime, { position: targetLocalPos }, { easing: "sineIn" })
                        .call(() => {
                            this.m_gameView.EffectPlate.RegisterTargetStopNode(newPosition, capturedInfo.node, capturedInfo.prefabKey);
                        })
                        .start();
                } else {
                    // 沒有 spine → 落地後建新的
                    const targetFallDone = colPromises[row];
                    allPromises.push(targetFallDone.then(() => {
                        this.m_gameView.EffectPlate.ReelStopEffect(capturedCol, capturedRow, symbolId, null);
                    }));
                }
            }
        }
    }
}

